+export class AgentDBBackend {
+  constructor(options = {}) {
+    this.dbPath = options.dbPath || '.agentdb/claude-flow.db';
+    this.quantization = options.quantization || 'scalar'; // scalar, binary, product
+    this.enableHNSW = options.enableHNSW !== false;
