+        path: this.dbPath,
+        quantization: this.quantization,
+        indexType: this.enableHNSW ? 'hnsw' : 'flat',
+      });
+
+      await this.db.init();
+      this.initialized = true;
+
+      console.error(
+        `[${new Date().toISOString()}] INFO [agentdb-backend] AgentDB initialized at ${this.dbPath}`,
+      );
+      console.error(
