+    }
+
+    try {
+      await this.db.add({
+        id: key,
+        vector: embedding,
+        metadata: {
+          ...metadata,
+          storedAt: Date.now(),
+        },
+      });
+    } catch (error) {
+      console.error(
+        `[${new Date().toISOString()}] ERROR [agentdb-backend] Failed to store vector: ${error.message}`,
+      );
